SELECT r.id, r.role_id, r.obj_type, r.project_id, r.obj_id, r.can_read, r.can_edit, r.note, r.create_by, r.create_time, r.update_by, r.update_time, r.sys_org_code, sr.role_name, ip.name as project_name FROM ietm_roleauth r LEFT JOIN sys_role sr ON r.role_id = sr.id LEFT JOIN ietm_project ip ON r.project_id = ip.id WHERE 1=1
AND r.obj_type = #{objType}
AND r.obj_id = #{objId}
ORDER BY r.create_time DESC

SELECT r.id, r.role_id, r.obj_type, r.project_id, r.obj_id, r.can_read, r.can_edit, r.note, r.create_by, r.create_time, r.update_by, r.update_time, r.sys_org_code, sr.role_name, ip.name as project_name FROM ietm_roleauth r LEFT JOIN sys_role sr ON r.role_id = sr.id LEFT JOIN ietm_project ip ON r.project_id = ip.id WHERE r.project_id = #{projectId}
AND r.obj_type = #{objType}
ORDER BY r.create_time DESC
